#include <algorithm>

using namespace std;

/**
 * @brief 解决最大固定点数量问题
 * 
 * @param nums 整数数组
 * @return int64 最大固定点数量
 */
int64 solve(vector<int64> nums) {
    // 这个问题可以转化为找到一个最长递增子序列（LIS）的变种。
    // 假设我们选择了一组元素 {nums[i_1], nums[i_2], ..., nums[i_k]} 
    // 它们保持在数组中的相对顺序 i_1 < i_2 < ... < i_k。
    // 当这些元素被保留时，它们在新数组中的下标分别是 0, 1, ..., k-1。
    // 为了形成一个固定点，我们需要新数组中第 j 个元素的值等于 j。
    // 即，我们希望找到一个子序列 (i_1, i_2, ..., i_k) 使得：
    // nums[i_1] == 0
    // nums[i_2] == 1
    // ...
    // nums[i_k] == k-1
    // 并且 i_1 < i_2 < ... < i_k。
    // 这正是找到一个长度最大的、满足特定值的子序列问题。

    int current_target = 0; // 我们当前期望的固定点值 (即新数组的下标)
    int count = 0;          // 已经找到的固定点数量

    for (size_t i = 0; i < nums.size(); ++i) {
        // 如果当前元素的值等于我们当前期望的固定点值
        if (nums[i] == current_target) {
            // 找到一个匹配的元素，将其保留下来（相当于删除其他元素使其移动到当前位置）
            count++;
            // 移动到下一个期望的固定点值
            current_target++;
        }
    }

    return (int64)count;
}
