#include <vector>
#include <algorithm>

using namespace std;

/**
 * @brief 求解最大固定点数量。
 * 
 * 核心思想是：我们希望选择一个子序列，使得在子序列中，第 i 个元素的值等于 i。
 * 设我们选择的子序列的元素原索引为 $i_0, i_1, i_2, \dots, i_{k-1}$，其中 $i_0 < i_1 < \dots < i_{k-1}$。
 * 在新的序列中，第 j 个元素的值是 $nums[i_j]$，它的新下标是 $j$。
 * 为了形成固定点，我们要求 $nums[i_j] = j$。
 * 
 * 这个问题可以转化为：找到一个最长的子序列 $i_0, i_1, \dots, i_{k-1}$，使得：
 * 1. $i_0 < i_1 < \dots < i_{k-1}$
 * 2. $nums[i_j] = j$ 对于所有 $j=0, 1, \dots, k-1$。
 * 
 * 观察条件 $nums[i_j] = j$：
 * 如果我们固定最终的固定点数量为 $k$，那么我们必须找到 $k$ 个原索引 $i_0, i_1, \dots, i_{k-1}$，满足：
 * $nums[i_0] = 0$
 * $nums[i_1] = 1$
 * $\dots$
 * $nums[i_{k-1}] = k-1$
 * 并且 $i_0 < i_1 < \dots < i_{k-1}$。
 * 
 * 这正是最长递增子序列（LIS）的一个变种，但由于目标值是固定的 $0, 1, 2, \dots$，我们只需要一个贪心/计数策略。
 * 
 * 我们可以遍历原数组 `nums`，维护一个我们希望在新的序列中达到的下一个固定点值 $target = 0, 1, 2, \dots$。
 * 
 * 当我们遍历到 $nums[i]$ 时，如果 $nums[i]$ 等于当前的 $target$，这意味着我们可以选择 $nums[i]$ 作为下一个固定点。
 * 选择了它后，我们就可以尝试寻找下一个固定点，所以我们将 $target$ 增加 1。
 * 
 * 由于我们是顺序遍历 $i$，如果 $nums[i] = target$，那么任何满足 $nums[j] = target$ 且 $j < i$ 的选择都已经处理过了（或者没有选择）。
 * 贪心地选择第一个能满足 $nums[i] = target$ 的元素，可以保证我们为后续的更大的 $target'$ 留出尽可能多的剩余元素。
 * 
 * 算法流程：
 * 1. 初始化当前期望的固定点值 $target = 0$。
 * 2. 遍历 $i$ 从 $0$ 到 $nums.size() - 1$。
 * 3. 如果 $nums[i] == target$，说明我们找到了一个可以形成固定点的元素。我们选择它（即删除所有其他元素，使得它在新序列中位于下标 $target$），然后增加 $target$（寻找下一个固定点 $target+1$）。
 * 4. 最终的 $target$ 值就是最大的固定点数量。
 * 
 * 复杂度分析：时间复杂度 $O(N)$，空间复杂度 $O(1)$。
 */
class Solution {
public:
    int64_t solve(vector<int64_t> nums) {
        int64_t target = 0;
        for (int64_t i = 0; i < nums.size(); ++i) {
            // nums[i] 的值需要等于它在最终序列中的下标 target
            if (nums[i] == target) {
                target++;
            }
        }
        return target;
    }
};
