    // target_index 表示我们当前正在尝试匹配的固定点位置 j (即我们期望的 nums[i] 的值)。
    long long target_index = 0;
    int n = nums.size();

    for (int i = 0; i < n; ++i) {
        // 检查当前元素 nums[i] 是否等于我们当前期望的固定点值 target_index。
        if (nums[i] == target_index) {
            // 如果相等，说明我们找到了一个可以成为固定点的元素。我们“保留”它。
            // 成功匹配一个固定点，所以我们期望下一个元素匹配的位置是 target_index + 1。
            target_index++;
        }
        // 如果不相等，我们选择删除 nums[i]（或者忽略它），继续寻找下一个可以匹配 target_index 的元素。
    }

    // target_index 记录的是成功匹配的固定点数量 + 1 (因为它从 0 开始计数，最后增加了一次)。
    // 因此，最大固定点数量就是 target_index - 1。
    return target_index;
}
